SELECT FROM posts p WHERE p.deleted = 0
AND p.category_id = #{categoryId}
AND p.id IN (SELECT pt.post_id FROM post_tags pt WHERE pt.tag_id = #{tagId} AND pt.deleted = 0)
AND (p.title ILIKE CONCAT('%', #{keyword}, '%') OR p.content_text ILIKE CONCAT('%', #{keyword}, '%'))
AND p.status = #{status}
AND p.author_id = #{userId}
AND EXISTS (SELECT 1 FROM follows WHERE follower_id = #{followingUserId} AND followee_id = p.author_id AND deleted = 0)
ORDER BY p.is_pinned DESC, p.pinned_at DESC,
p.view_count DESC p.like_count DESC p.comment_count DESC p.create_time DESC

SELECT 
FROM posts p
WHERE p.deleted = 0 AND p.status = 1
  AND p.create_time >= #{startTime}
ORDER BY p.view_count DESC, p.like_count DESC
LIMIT #{limit}
